            </Button>
        </Link>
        {
            notes.map(note => {
                return (
                <Card style={{margin:10}}>
                    <Card.Header style={{display:"flex"}}>
                        <span style={{
                            color: "black",
                            textDecoration: "none",
                            flex: 1,
                            cursor: "pointer",
                            alignSelf: "center",
                            fontSize: 18,
                        }}>{note.title}</span>
                    <div>
                        <Button href={`/note/${note._id}`}>Edit</Button>
                        <Button variant="danger" className="mx-2" onClick={() => deleteHandler(note._id)}>Delete</Button>
                    </div>
                    </Card.Header>
                </Card>
                )
            })

        }
    </MainScreen>
  )
}
